qry:select.qry:xquery:
	for $r in sql('
	SELECT           
		{%? (#PARAMIN:@orden!=''){% {%= #PARAMIN:@orden %} as Orden,%}{% %} %}
		MED04_HIST_CLINICA.oi_consulta_per, 
		MED04_HIST_CLINICA.oi_personal_emp,
		MED04_HIST_CLINICA.f_fechahora_cons, 
		MED04_HIST_CLINICA.oi_motivo_consulta,
		MED04_HIST_CLINICA.f_baja, 
		MED04_HIST_CLINICA.f_alta, 
		MED04_HIST_CLINICA.e_dias_perdidos,
		MED04_HIST_CLINICA.o_consulta_per,
		MED04_HIST_CLINICA.oi_enfermedad,
		MED04_HIST_CLINICA.f_prox_consulta,
		MED04_HIST_CLINICA.f_prev_alta,
		ORG03_UBICACIONES.c_ubicacion,
		ORG03_UBICACIONES.d_ubicacion,
		PER02_PERSONAL_EMP.f_ingreso,
		ORG04_POSICIONES.d_posicion,
		ORG04_PUESTOS.d_puesto,
		ORG18_CATEGORIAS.d_categoria,
		ORG08_CS_COSTO.d_centro_costo,
		PER35_MOD_CONTR.d_mod_contr
		{%? (#PARAMIN:@oi_medico != '' AND #PARAMIN:@oi_empresa_medica = '') 
			{% , MED04_DETALLE_HIST.oi_medico %} 
			{% %} 
		%}
		{%? (#PARAMIN:@oi_empresa_medica != '') 
			{%, MED04_DETALLE_HIST.oi_medico, MED03_MEDICOS.oi_empresa_medica %} 
			{% %} 
		%}
	FROM 
		MED04_HIST_CLINICA, 
		PER02_PERSONAL_EMP,
		ORG03_UBICACIONES,
		ORG04_POSICIONES,
		ORG04_PUESTOS,
		ORG18_CATEGORIAS,
		ORG08_CS_COSTO,
		PER35_MOD_CONTR
		{%? (#PARAMIN:@oi_medico != '' AND #PARAMIN:@oi_empresa_medica = '' OR #PARAMIN:@agrupacion ='3') 
			{% , MED04_DETALLE_HIST %} 
			{% %} 
		%}
		{%? (#PARAMIN:@oi_empresa_medica != '' OR #PARAMIN:@agrupacion ='4')
			{%, MED04_DETALLE_HIST, MED03_MEDICOS, MED02_EMPRESAS %} 
			{% %} 
		%}

	JOIN 
		MED04_HIST_CLINICA.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp,					
		PER02_PERSONAL_EMP.oi_ubicacion LEFT OUTER ORG03_UBICACIONES.oi_ubicacion,
		PER02_PERSONAL_EMP.oi_posicion_ult  LEFT OUTER ORG04_POSICIONES.oi_posicion,
		PER02_PERSONAL_EMP.oi_puesto_ult  LEFT OUTER ORG04_PUESTOS.oi_puesto,
		PER02_PERSONAL_EMP.oi_categoria_ult  LEFT OUTER ORG18_CATEGORIAS.oi_categoria,
		PER02_PERSONAL_EMP.oi_ctro_costo_ult LEFT OUTER ORG08_CS_COSTO.oi_centro_costo,
		PER02_PERSONAL_EMP.oi_mod_contr  LEFT OUTER  PER35_MOD_CONTR.oi_mod_contr
		{%? (#PARAMIN:@oi_medico != '' AND #PARAMIN:@oi_empresa_medica = '' OR #PARAMIN:@agrupacion ='3') 
			{% ,	MED04_HIST_CLINICA.oi_consulta_per INNER MED04_DETALLE_HIST.oi_consulta_per %} 
			{% %} 
		%}
		{%? (#PARAMIN:@oi_empresa_medica != '' OR #PARAMIN:@agrupacion ='4') 
			{% ,	MED04_HIST_CLINICA.oi_consulta_per INNER MED04_DETALLE_HIST.oi_consulta_per 
				 ,	MED03_MEDICOS.oi_medico INNER MED04_DETALLE_HIST.oi_medico
				 ,	MED03_MEDICOS.oi_empresa_medica INNER MED02_EMPRESAS.oi_empresa_medica%} 
			{% %} 
		%}

	WHERE 
		PER02_PERSONAL_EMP.oi_empresa = {#PARAMIN:@oi_empresa} AND
		PER02_PERSONAL_EMP.oi_personal_emp in ({%=#PARAMIN:@values%})
		{%? (#PARAMIN:@f_desde!= '') {% AND MED04_HIST_CLINICA.f_fechahora_cons > {Datetime(#PARAMIN:@f_desde)} %} {% %} %} 
		{%? (#PARAMIN:@f_hasta != '') {% AND MED04_HIST_CLINICA.f_fechahora_cons < {Datetime(Number(Datetime(#PARAMIN:@f_hasta))+1)} %} {% %} %}					
		{%? (#PARAMIN:@oi_motivo_consulta != '') {% AND MED04_HIST_CLINICA.oi_motivo_consulta = {#PARAMIN:@oi_motivo_consulta} %} {% %} %}
		{%? (#PARAMIN:@oi_enfermedad != '') {% AND MED04_HIST_CLINICA.oi_enfermedad = {#PARAMIN:@oi_enfermedad} %} {% %} %}
		{%? (#PARAMIN:@oi_medico != '') {% AND MED04_DETALLE_HIST.oi_medico = {#PARAMIN:@oi_medico} %} {% %} %}
		{%? (#PARAMIN:@oi_empresa_medica != '') {% AND MED03_MEDICOS.oi_empresa_medica = {#PARAMIN:@oi_empresa_medica} %} {% %} %}

		{%? (#AGRUP:@agrupacion != '')  {%=#AGRUP:@agrupacion%} {% %} %}					

	 {%? (#PARAMIN:@orden!='') 
			{%ORDER BY orden ASC %} 
			{% %} 
		%}  

')/ROWS/ROW
